package day0315;

public class Ex1DataType {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		// 짧은주석
		/*
		 긴주석
		 */
		
		// 기본 자료형 공부
		boolean flag = true;
		boolean flag2;
		flag2 = false;
		
		System.out.println(flag);
		System.out.println(flag2);
		System.out.println(!flag);
		System.out.println(!flag2);
		
		System.out.println(flag && flag2);
		System.out.println(flag || flag2);
	}

}

